  { to: "/formations", icon: GraduationCap, label: "Formations", allowedRoles: ["simple_utilisateur", "responsable", "administrateur"] as AppRole[] },
  { to: "/formateurs", icon: UserCheck, label: "Formateurs", allowedRoles: ["simple_utilisateur", "responsable", "administrateur"] as AppRole[] },
  { to: "/participants", icon: Users, label: "Participants", allowedRoles: ["simple_utilisateur", "responsable", "administrateur"] as AppRole[] },
  { to: "/employeurs", icon: Briefcase, label: "Employeurs", allowedRoles: ["simple_utilisateur", "responsable", "administrateur"] as AppRole[] },
  { to: "/domaines", icon: Layers, label: "Domaines", allowedRoles: ["administrateur"] as AppRole[] },
  { to: "/structures", icon: Building2, label: "Structures", allowedRoles: ["administrateur"] as AppRole[] },
  { to: "/profils", icon: BookOpen, label: "Profils", allowedRoles: ["administrateur"] as AppRole[] },
  { to: "/utilisateurs", icon: Settings, label: "Utilisateurs", allowedRoles: ["administrateur"] as AppRole[] },
