export type AppRole = "simple_utilisateur" | "responsable" | "administrateur";

export const normalizeRole = (role?: string | null): AppRole | null => {
  if (!role) return null;

  // Accept legacy formats such as ROLE_ADMINISTRATEUR, "simple utilisateur", or "admin".
  const cleaned = role.trim().toLowerCase().replace(/[\s-]+/g, "_");
  const normalized = cleaned.startsWith("role_") ? cleaned.slice(5) : cleaned;

  if (normalized === "simple_utilisateur" || normalized === "simpleutilisateur" || normalized === "simple") {
    return "simple_utilisateur";
  }
  if (normalized === "responsable") {
    return "responsable";
  }
  if (normalized === "administrateur" || normalized === "admin") {
    return "administrateur";
  }

  return null;
};

export const canAccessRole = (allowedRoles: AppRole[], role?: string | null) => {
  const normalizedRole = normalizeRole(role);
  return normalizedRole ? allowedRoles.includes(normalizedRole) : false;
};

export const getDefaultRoute = (role?: string | null) => {
  const normalizedRole = normalizeRole(role);
  if (normalizedRole === "simple_utilisateur") {
    return "/formations";
  }
  if (normalizedRole === "responsable" || normalizedRole === "administrateur") {
    return "/dashboard";
  }
  return "/login";
};

import { useEffect, useMemo, useState } from "react";
import { GraduationCap, Users, UserCheck, DollarSign, TrendingUp, BarChart3, Building2 } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from "recharts";
import StatCard from "@/components/shared/StatCard";
import API from "@/services/api";
import { Formation, Formateur, Participant } from "@/types";

interface DomaineStat {
  domaineId: number | null;
  domaine: string;
  count: number;
  budgetTotal: number;
}

interface StructureStat {
  structureId: number | null;
  structure: string;
  count: number;
}

interface AnneeStat {
  annee: number;
  count: number;
  budgetTotal: number;
}

interface StatistiquesResponse {
  totalFormations: number;
  totalParticipants: number;
  totalBudget?: number;
  budgetMoyen?: number;
  formationsParDomaine?: DomaineStat[];
  participantsParStructure?: StructureStat[];
  formationsParAnnee?: AnneeStat[];
}

const formatMoney = (value: number) => `${new Intl.NumberFormat("fr-FR").format(Math.round(value))} DT`;
const formatCompactMoney = (value: number) => `${(value / 1000).toFixed(1)}k DT`;

const DASHBOARD_COLORS = [
  "#0ea5a4",
  "#3b82f6",
  "#22c55e",
  "#f59e0b",
  "#a855f7",
  "#ef4444",
  "#14b8a6",
  "#6366f1",
];

const Dashboard = () => {
  const [formations, setFormations] = useState<Formation[]>([]);
  const [formateurs, setFormateurs] = useState<Formateur[]>([]);
  const [participants, setParticipants] = useState<Participant[]>([]);
  const [stats, setStats] = useState<StatistiquesResponse | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const loadData = async () => {
      try {
        const formationsRes = await API.get("/formations");
        const [formateursRes, participantsRes, statsRes] = await Promise.all([
          API.get("/formateurs"),
          API.get("/participants"),
          API.get("/statistiques"),
        ]);

        setFormations(formationsRes.data || []);
        setFormateurs(formateursRes.data || []);
        setParticipants(participantsRes.data || []);
        setStats(statsRes.data || null);
      } catch (error) {
        console.error("Erreur dashboard:", error);
      } finally {
        setIsLoading(false);
      }
    };
    
    loadData();
  }, []);

  const totalBudget = stats?.totalBudget ?? formations.reduce((sum, f) => sum + (f.budget ?? 0), 0);
  const budgetMoyen = stats?.budgetMoyen ?? (formations.length ? totalBudget / formations.length : 0);

  const formationsParAnnee = useMemo(() => {
    if (stats?.formationsParAnnee?.length) {
      return [...stats.formationsParAnnee]
        .sort((a, b) => a.annee - b.annee)
        .map((s) => ({ annee: String(s.annee), count: s.count, budget: s.budgetTotal ?? 0 }));
    }

    const grouped = formations.reduce<Record<number, { count: number; budget: number }>>((acc, current) => {
      const year = current.annee;
      if (!acc[year]) acc[year] = { count: 0, budget: 0 };
      acc[year].count += 1;
      acc[year].budget += current.budget ?? 0;
      return acc;
    }, {});

    return Object.entries(grouped)
      .sort(([a], [b]) => Number(a) - Number(b))
      .map(([annee, value]) => ({ annee, count: value.count, budget: value.budget }));
  }, [formations, stats]);

  const formationsParDomaine = useMemo(() => {
    const source = stats?.formationsParDomaine?.length
      ? stats.formationsParDomaine.map((s) => ({ name: s.domaine, count: s.count, budget: s.budgetTotal }))
      : (() => {
          const grouped = new Map<string, { count: number; budget: number }>();
          formations.forEach((formation) => {
            const name = formation.domaine?.libelle ?? "Sans domaine";
            const current = grouped.get(name) ?? { count: 0, budget: 0 };
            grouped.set(name, {
              count: current.count + 1,
              budget: current.budget + (formation.budget ?? 0),
            });
          });
          return Array.from(grouped.entries()).map(([name, value]) => ({ name, count: value.count, budget: value.budget }));
        })();

    return source
      .sort((a, b) => b.count - a.count)
      .map((item, index) => ({ ...item, color: DASHBOARD_COLORS[index % DASHBOARD_COLORS.length] }));
  }, [formations, stats]);

  const participantsParStructure = useMemo(() => {
    if (stats?.participantsParStructure?.length) {
      return [...stats.participantsParStructure]
        .map((s) => ({ structure: s.structure, count: s.count }))
        .sort((a, b) => b.count - a.count);
    }

    const grouped = new Map<string, number>();
    participants.forEach((participant) => {
      const key = participant.structure?.libelle ?? "Sans structure";
      grouped.set(key, (grouped.get(key) ?? 0) + 1);
    });

    return Array.from(grouped.entries())
      .map(([structure, count]) => ({ structure, count }))
      .sort((a, b) => b.count - a.count);
  }, [participants, stats]);

  const topDomaines = formationsParDomaine.slice(0, 6);
  const topStructures = participantsParStructure.slice(0, 8);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <p className="text-muted-foreground">Chargement des données...</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div>
        <h1 className="page-header">Tableau de bord</h1>
        <p className="text-muted-foreground text-sm mt-1">
          Vue d&apos;ensemble des activités de formation — Excellent Training
        </p>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
        <StatCard title="Formations" value={stats?.totalFormations ?? formations.length} icon={GraduationCap} color="primary" />
        <StatCard title="Participants" value={stats?.totalParticipants ?? participants.length} icon={Users} color="info" />
        <StatCard title="Formateurs" value={formateurs.length} icon={UserCheck} color="success" />
        <StatCard title="Budget Total" value={formatCompactMoney(totalBudget)} icon={DollarSign} color="warning" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="stat-card">
          <div className="flex items-center justify-between mb-2">
            <h3 className="font-semibold text-foreground">Budget moyen par formation</h3>
            <DollarSign className="w-5 h-5 text-warning" />
          </div>
          <p className="text-2xl font-bold text-foreground">{formatMoney(budgetMoyen)}</p>
          <p className="text-sm text-muted-foreground mt-1">Indicateur de pilotage financier global.</p>
        </div>

        <div className="stat-card">
          <div className="flex items-center justify-between mb-2">
            <h3 className="font-semibold text-foreground">Concentration formation / domaine</h3>
            <TrendingUp className="w-5 h-5 text-primary" />
          </div>
          {topDomaines.length === 0 ? (
            <p className="text-sm text-muted-foreground">Aucune donnée disponible.</p>
          ) : (
            <p className="text-2xl font-bold text-foreground">
              {topDomaines[0].name} ({topDomaines[0].count})
            </p>
          )}
          <p className="text-sm text-muted-foreground mt-1">Domaine le plus actif sur la période.</p>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Bar chart */}
        <div className="stat-card">
          <div className="flex items-center gap-2 mb-6">
            <BarChart3 className="w-5 h-5 text-primary" />
            <h3 className="font-semibold text-foreground">Formations par année</h3>
          </div>
          <ResponsiveContainer width="100%" height={280}>
            <BarChart data={formationsParAnnee}>
              <CartesianGrid strokeDasharray="3 3" stroke="hsl(214, 20%, 90%)" />
              <XAxis dataKey="annee" tick={{ fontSize: 12 }} />
              <YAxis allowDecimals={false} tick={{ fontSize: 12 }} />
              <Tooltip
                formatter={(value: number, name) => [name === "budget" ? formatMoney(value) : value, name === "budget" ? "Budget" : "Formations"]}
                contentStyle={{
                  borderRadius: "12px",
                  border: "1px solid hsl(214, 20%, 90%)",
                  boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                }}
              />
              <Bar dataKey="count" name="Formations" fill="hsl(168, 80%, 36%)" radius={[6, 6, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Pie chart */}
        <div className="stat-card">
          <div className="flex items-center gap-2 mb-6">
            <TrendingUp className="w-5 h-5 text-primary" />
            <h3 className="font-semibold text-foreground">Répartition par domaine</h3>
          </div>
          {topDomaines.length === 0 ? (
            <p className="text-sm text-muted-foreground">Aucune donnée disponible.</p>
          ) : (
            <ResponsiveContainer width="100%" height={280}>
              <PieChart>
                <Pie
                  data={topDomaines}
                  cx="50%"
                  cy="50%"
                  innerRadius={58}
                  outerRadius={100}
                  paddingAngle={4}
                  dataKey="count"
                  nameKey="name"
                >
                  {topDomaines.map((d, index) => (
                    <Cell key={`${d.name}-${index}`} fill={d.color} />
                  ))}
                </Pie>
                <Legend />
                <Tooltip
                  formatter={(value: number, name, payload) => {
                    if (name === "count") return [value, "Formations"];
                    return [formatMoney((payload?.payload as { budget?: number })?.budget ?? 0), "Budget"];
                  }}
                  contentStyle={{
                    borderRadius: "12px",
                    border: "1px solid hsl(214, 20%, 90%)",
                    boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                  }}
                />
              </PieChart>
            </ResponsiveContainer>
          )}
        </div>
      </div>

      {/* New advanced charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="stat-card">
          <div className="flex items-center gap-2 mb-4">
            <Building2 className="w-5 h-5 text-primary" />
            <h3 className="font-semibold text-foreground">Suivi avancé par structure</h3>
          </div>
          {topStructures.length === 0 ? (
            <p className="text-sm text-muted-foreground">Aucune donnée disponible.</p>
          ) : (
            <ResponsiveContainer width="100%" height={280}>
              <BarChart data={topStructures} layout="vertical" margin={{ left: 10, right: 20 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(214, 20%, 90%)" />
                <XAxis type="number" allowDecimals={false} tick={{ fontSize: 12 }} />
                <YAxis dataKey="structure" type="category" width={140} tick={{ fontSize: 12 }} />
                <Tooltip
                  formatter={(value: number) => [value, "Participants"]}
                  contentStyle={{
                    borderRadius: "12px",
                    border: "1px solid hsl(214, 20%, 90%)",
                    boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                  }}
                />
                <Bar dataKey="count" fill="hsl(142, 72%, 40%)" radius={[0, 6, 6, 0]} />
              </BarChart>
            </ResponsiveContainer>
          )}
        </div>

        <div className="stat-card">
          <div className="flex items-center gap-2 mb-6">
            <TrendingUp className="w-5 h-5 text-primary" />
            <h3 className="font-semibold text-foreground">Budget par domaine</h3>
          </div>
          {topDomaines.length === 0 ? (
            <p className="text-sm text-muted-foreground">Aucune donnée disponible.</p>
          ) : (
            <ResponsiveContainer width="100%" height={280}>
              <BarChart data={topDomaines} layout="vertical" margin={{ left: 10, right: 20 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(214, 20%, 90%)" />
                <XAxis type="number" tick={{ fontSize: 12 }} />
                <YAxis dataKey="name" type="category" width={140} tick={{ fontSize: 12 }} />
                <Tooltip
                  formatter={(value: number) => [formatMoney(value), "Budget"]}
                  contentStyle={{
                    borderRadius: "12px",
                    border: "1px solid hsl(214, 20%, 90%)",
                    boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                  }}
                />
                <Bar dataKey="budget" fill="hsl(210, 90%, 55%)" radius={[0, 6, 6, 0]} />
              </BarChart>
            </ResponsiveContainer>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import API from "@/services/api";
import { Domaine } from "@/types";
import { useToast } from "@/hooks/use-toast";

const DomainesPage = () => {
  const [domaines, setDomaines] = useState<Domaine[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const { toast } = useToast();

  useEffect(() => {
    loadDomaines();
  }, []);

  const loadDomaines = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/domaines");
      setDomaines(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      toast({ title: "Erreur", description: "Impossible de charger les domaines" });
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (domaine: Domaine) => {
    if (window.confirm("Êtes-vous sûr de vouloir supprimer ce domaine ?")) {
      try {
        await API.delete(`/domaines/${domaine.id}`);
        toast({ title: "Succès", description: "Domaine supprimé" });
        loadDomaines();
      } catch (error) {
        console.error("Erreur:", error);
        toast({ title: "Erreur", description: "Impossible de supprimer le domaine" });
      }
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "libelle", label: "Libellé" },
  ];

  return (
    <DataTable<Domaine>
      title="Domaines"
      description="Gérer les domaines de formation"
      columns={columns}
      data={domaines}
      searchKey="libelle"
      searchPlaceholder="Rechercher un domaine..."
      isLoading={isLoading}
      onAdd={() => toast({ title: "Ajouter un domaine", description: "Fonctionnalité à venir" })}
      onEdit={() => toast({ title: "Modifier", description: "Fonctionnalité à venir" })}
      onDelete={handleDelete}
    />
  );
};

