import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import CrudFormModal from "@/components/shared/CrudFormModal";
import API from "@/services/api";
import { Employeur, Formateur } from "@/types";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";

const FormateursPage = () => {
  const [formateurs, setFormateurs] = useState<Formateur[]>([]);
  const [employeurs, setEmployeurs] = useState<Employeur[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingFormateur, setEditingFormateur] = useState<Formateur | null>(null);
  const [formValues, setFormValues] = useState<Record<string, string>>({
    nom: "",
    prenom: "",
    email: "",
    tel: "",
    type: "interne",
    employeurId: "",
  });
  const [formError, setFormError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  const notify = (title: string, description: string) =>
    toast({ id: Date.now().toString(), title, description });

  useEffect(() => {
    loadFormateurs();
    loadEmployeurs();
  }, []);

  const loadEmployeurs = async () => {
    try {
      const res = await API.get("/employeurs");
      setEmployeurs(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
    }
  };

  const loadFormateurs = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/formateurs");
      setFormateurs(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de charger les formateurs");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (formateur: Formateur) => {
    try {
      await API.delete(`/formateurs/${formateur.id}`);
      notify("Succès", "Formateur supprimé");
      loadFormateurs();
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de supprimer le formateur");
    }
  };

  const openAddModal = () => {
    setEditingFormateur(null);
    setFormValues({ nom: "", prenom: "", email: "", tel: "", type: "interne", employeurId: "" });
    setFormError("");
    setIsModalOpen(true);
  };

  const openEditModal = (formateur: Formateur) => {
    setEditingFormateur(formateur);
    setFormValues({
      nom: formateur.nom ?? "",
      prenom: formateur.prenom ?? "",
      email: formateur.email ?? "",
      tel: formateur.tel ?? "",
      type: formateur.type ?? "interne",
      employeurId: formateur.employeur?.id ? String(formateur.employeur.id) : "",
    });
    setFormError("");
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    const nom = formValues.nom.trim();
    const prenom = formValues.prenom.trim();
    const email = formValues.email.trim();
    const tel = formValues.tel.trim();
    const type = formValues.type.trim().toLowerCase();
    const employeurId = formValues.employeurId ? Number(formValues.employeurId) : undefined;

    if (!nom || !prenom) {
      setFormError("Nom et prénom sont obligatoires");
      return;
    }

    if (type !== "interne" && type !== "externe") {
      setFormError("Le type doit être interne ou externe");
      return;
    }

    if (formValues.employeurId && (!Number.isInteger(employeurId) || employeurId <= 0)) {
      setFormError("Employeur invalide");
      return;
    }

    setIsSubmitting(true);
    setFormError("");
    try {
      const payload = {
        id: editingFormateur?.id,
        nom,
        prenom,
        email: email || null,
        tel: tel || null,
        type,
        employeur: employeurId ? { id: employeurId } : null,
      };

      if (editingFormateur) {
        await API.put(`/formateurs/${editingFormateur.id}`, payload);
        notify("Succès", "Formateur modifié");
      } else {
        await API.post("/formateurs", payload);
        notify("Succès", "Formateur ajouté");
      }

      setIsModalOpen(false);
      loadFormateurs();
    } catch (error) {
      console.error("Erreur:", error);
      setFormError(editingFormateur ? "Impossible de modifier le formateur" : "Impossible d'ajouter le formateur");
    } finally {
      setIsSubmitting(false);
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "nom", label: "Nom" },
    { key: "prenom", label: "Prénom" },
    { key: "email", label: "Email" },
    { key: "tel", label: "Téléphone" },
    {
      key: "type",
      label: "Type",
      render: (f: Formateur) => <Badge variant={f.type === "interne" ? "secondary" : "outline"}>{f.type || "—"}</Badge>,
    },
    {
      key: "employeurId",
      label: "Employeur ID",
      render: (f: Formateur) => f.employeur?.id ?? "—",
    },
    {
      key: "employeur",
      label: "Employeur",
      render: (f: Formateur) => (f.employeur ? `#${f.employeur.id} - ${f.employeur.nomEmployeur}` : "—"),
    },
  ];

  return (
    <>
      <DataTable<Formateur>
        title="Formateurs"
        description="Gérer les formateurs"
        columns={columns}
        data={formateurs}
        searchPlaceholder="Rechercher un formateur..."
        isLoading={isLoading}
        onAdd={openAddModal}
        onEdit={openEditModal}
        onDelete={handleDelete}
      />
      <CrudFormModal
        open={isModalOpen}
        title={editingFormateur ? "Modifier un formateur" : "Ajouter un formateur"}
        fields={[
          { key: "nom", label: "Nom", required: true },
          { key: "prenom", label: "Prénom", required: true },
          { key: "email", label: "Email", type: "email" },
          { key: "tel", label: "Téléphone" },
          {
            key: "type",
            label: "Type",
            type: "select",
            required: true,
            options: [
              { value: "interne", label: "Interne" },
              { value: "externe", label: "Externe" },
            ],
          },
          {
            key: "employeurId",
            label: "Employeur",
            type: "select",
            options: employeurs.map((e) => ({ value: String(e.id), label: `#${e.id} - ${e.nomEmployeur}` })),
          },
        ]}
        values={formValues}
        error={formError}
        isSubmitting={isSubmitting}
        submitLabel={editingFormateur ? "Modifier" : "Ajouter"}
        onChange={(key, value) => setFormValues((prev) => ({ ...prev, [key]: value }))}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleSubmit}
      />
    </>
  );
};

export default FormateursPage;

