      onEdit={() => toast({ title: "Modifier", description: "Fonctionnalité à venir" })}
      onDelete={handleDelete}
    />
    <>
      <DataTable<Formation>
        title="Formations"
        description="Gérer les formations organisées par le centre"
        columns={columns}
        data={formations}
        searchKey="titre"
