  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingFormation, setEditingFormation] = useState<Formation | null>(null);
  const [formValues, setFormValues] = useState<Record<string, string>>({
    titre: "",
    nom: "",
    description: "",
    annee: "2026",
    duree: "1",
    budget: "0",
    dateFormation: "",
    lieu: "",
    domaineId: "",
    formateurId: "",
  });
  const [formError, setFormError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();
  const { userRole } = useAuth();
  const canManageFormations = canAccessRole(["responsable", "administrateur"], userRole);

  const notify = (title: string, description: string) =>
    toast({ id: Date.now().toString(), title, description });

  useEffect(() => {
    loadFormations();
    loadLookups();
  }, []);

  const loadLookups = async () => {
    if (!canManageFormations) {
      setDomaines([]);
      setFormateurs([]);
      return;
    }
    try {
      const [domainesRes, formateursRes] = await Promise.all([API.get("/domaines"), API.get("/formateurs")]);
      setDomaines(domainesRes.data || []);
      setFormateurs(formateursRes.data || []);
    } catch (error) {
      console.error("Erreur:", error);
    }
  };

  const loadFormations = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/formations");
      setFormations(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de charger les formations");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (formation: Formation) => {
    try {
      await API.delete(`/formations/${formation.id}`);
      notify("Succès", "Formation supprimée");
      loadFormations();
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de supprimer la formation");
    }
  };

  const openAddModal = () => {
    setEditingFormation(null);
    setFormValues({
      titre: "",
      nom: "",
      description: "",
      annee: "2026",
      duree: "1",
      budget: "0",
      dateFormation: "",
      lieu: "",
      domaineId: "",
      formateurId: "",
    });
    setFormError("");
    setIsModalOpen(true);
  };

  const openEditModal = (formation: Formation) => {
    setEditingFormation(formation);
    setFormValues({
      titre: formation.titre ?? "",
      nom: formation.nom ?? "",
      description: formation.description ?? "",
      annee: String(formation.annee ?? 2026),
      duree: String(formation.duree ?? 1),
      budget: String(formation.budget ?? 0),
      dateFormation: formation.dateFormation ?? "",
      lieu: formation.lieu ?? "",
      domaineId: formation.domaine?.id ? String(formation.domaine.id) : "",
      formateurId: formation.formateur?.id ? String(formation.formateur.id) : "",
    });
    setFormError("");
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    const titre = formValues.titre.trim();
    const nom = formValues.nom.trim();
    const description = formValues.description.trim();
    const annee = Number(formValues.annee);
    const duree = Number(formValues.duree);
    const budget = Number(formValues.budget);
    const dateFormation = formValues.dateFormation.trim();
    const lieu = formValues.lieu.trim();
    const domaineId = formValues.domaineId ? Number(formValues.domaineId) : undefined;
    const formateurId = formValues.formateurId ? Number(formValues.formateurId) : undefined;

    if (!titre || !nom || !description || !dateFormation || !lieu) {
      setFormError("Titre, nom, description, date et lieu sont obligatoires");
      return;
    }
    if (!Number.isInteger(annee) || annee < 2000) {
      setFormError("Année invalide");
      return;
    }
    if (!Number.isInteger(duree) || duree < 1) {
      setFormError("Durée invalide");
      return;
    }
    if (Number.isNaN(budget) || budget < 0) {
      setFormError("Budget invalide");
      return;
    }

    setIsSubmitting(true);
    setFormError("");
    try {
      const payload = {
        id: editingFormation?.id,
        titre,
        nom,
        description,
        annee,
        duree,
        budget,
        dateFormation,
        lieu,
        domaine: domaineId ? { id: domaineId } : null,
        formateur: formateurId ? { id: formateurId } : null,
      };

      if (editingFormation) {
        await API.put(`/formations/${editingFormation.id}`, payload);
        notify("Succès", "Formation modifiée");
      } else {
        await API.post("/formations", payload);
        notify("Succès", "Formation ajoutée");
      }

      setIsModalOpen(false);
      loadFormations();
    } catch (error) {
      console.error("Erreur:", error);
      setFormError(editingFormation ? "Impossible de modifier la formation" : "Impossible d'ajouter la formation");
    } finally {
      setIsSubmitting(false);
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "titre", label: "Titre" },
    { key: "nom", label: "Nom" },
    {
      key: "description",
      label: "Description",
      render: (f: Formation) => <span className="max-w-xs whitespace-normal break-words block">{f.description}</span>,
    },
    { key: "dateFormation", label: "Date", render: (f: Formation) => f.dateFormation || "—" },
    { key: "lieu", label: "Lieu", render: (f: Formation) => f.lieu || "—" },
    {
      key: "domaineId",
      label: "Domaine ID",
      render: (f: Formation) => f.domaine?.id ?? "—",
    },
    {
      key: "domaine",
      label: "Domaine",
      render: (f: Formation) =>
        f.domaine ? (
          <Badge variant="secondary" className="font-normal">
            #{f.domaine.id} - {f.domaine.libelle}
          </Badge>
        ) : (
          "—"
        ),
    },
    { key: "annee", label: "Année" },
    { key: "duree", label: "Durée (j)" },
    {
      key: "budget",
      label: "Budget",
      render: (f: Formation) => `${f.budget.toLocaleString()} DT`,
    },
    {
      key: "formateurId",
      label: "Formateur ID",
      render: (f: Formation) => f.formateur?.id ?? "—",
    },
    {
      key: "formateur",
      label: "Formateur",
      render: (f: Formation) =>
        f.formateur ? (
          <Badge variant="outline" className="font-normal">
            #{f.formateur.id} - {f.formateur.prenom} {f.formateur.nom}
          </Badge>
        ) : (
          "—"
        ),
    },
    {
      key: "participants",
      label: "Participants",
      render: (f: Formation) => <Badge variant="outline">{f.participants?.length ?? "—"}</Badge>,
    },
  ];

  return (
    <>
      <DataTable<Formation>
        title="Formations"
        description="Gérer les formations organisées par le centre"
        columns={columns}
        data={formations}
        searchKey="titre"
        searchPlaceholder="Rechercher une formation..."
        isLoading={isLoading}
        onAdd={canManageFormations ? openAddModal : undefined}
        onEdit={canManageFormations ? openEditModal : undefined}
        onDelete={canManageFormations ? handleDelete : undefined}
      />
      <CrudFormModal
        open={isModalOpen}
        title={editingFormation ? "Modifier une formation" : "Ajouter une formation"}
        fields={[
          { key: "titre", label: "Titre", required: true },
          { key: "nom", label: "Nom", required: true },
          { key: "description", label: "Description", type: "textarea", required: true },
          { key: "annee", label: "Année", type: "number", required: true },
          { key: "duree", label: "Durée (jours)", type: "number", required: true },
          { key: "budget", label: "Budget", type: "number", required: true },
          { key: "dateFormation", label: "Date formation", type: "date", required: true },
          { key: "lieu", label: "Lieu", required: true },
          {
            key: "domaineId",
            label: "Domaine",
            type: "select",
            options: domaines.map((d) => ({ value: String(d.id), label: `#${d.id} - ${d.libelle}` })),
          },
          {
            key: "formateurId",
            label: "Formateur",
            type: "select",
            options: formateurs.map((f) => ({ value: String(f.id), label: `#${f.id} - ${f.prenom} ${f.nom}` })),
          },
        ]}
        values={formValues}
        error={formError}
        isSubmitting={isSubmitting}
        submitLabel={editingFormation ? "Modifier" : "Ajouter"}
        onChange={(key, value) => setFormValues((prev) => ({ ...prev, [key]: value }))}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleSubmit}
      />
    </>
  );
};

export default FormationsPage;

import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "@/context/AuthContext";
import API from "@/services/api";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { BookOpen } from "lucide-react";
import { getDefaultRoute, normalizeRole } from "@/lib/rbac";

const DEMO_ACCOUNTS: Record<string, { login: string; password: string }> = {
  simple_utilisateur: { login: "simple", password: "admin123" },
  responsable: { login: "responsable", password: "admin123" },
  administrateur: { login: "admin", password: "admin123" },
};

function Login() {
  const [selectedRole, setSelectedRole] = useState("administrateur");
  const [login, setLogin] = useState(DEMO_ACCOUNTS.administrateur.login);
  const [password, setPassword] = useState(DEMO_ACCOUNTS.administrateur.password);
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();
  const { login: authLogin } = useAuth();

  const handleRoleChange = (role: string) => {
    setSelectedRole(role);
    const account = DEMO_ACCOUNTS[role] ?? DEMO_ACCOUNTS.administrateur;
    setLogin(account.login);
    setPassword(account.password);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setIsLoading(true);

    if (!login.trim() || !password.trim()) {
      setError("Veuillez remplir tous les champs");
      setIsLoading(false);
      return;
    }

    try {
      console.log(" Tentative de connexion...", { login: login.trim() });
      const res = await API.post("/auth/login", { login: login.trim(), password: password.trim() });
      console.log("✅ Login réussi!", res.data);

      // Sauvegarder dans localStorage ET AuthContext
      authLogin(res.data);

      const targetRoute = getDefaultRoute(normalizeRole(res.data?.role) ?? normalizeRole(selectedRole));

      // Attendre un peu avant de naviguer pour laisser le state se mettre à jour
      setTimeout(() => {
        console.log(` Redirection vers ${targetRoute}...`);
        navigate(targetRoute, { replace: true });
      }, 500);
    } catch (err: any) {
      console.error("❌ Erreur login complète:", err);
      let errorMsg = "Erreur de connexion";

      if (err.code === "ECONNABORTED") {
        errorMsg = "Timeout - Le serveur ne répond pas";
      } else if (err.message === "Network Error") {
        errorMsg = "Erreur réseau - Le backend est-il disponible?";
      } else if (err.response?.status === 401) {
        errorMsg = "Login ou mot de passe incorrect";
      } else if (err.response?.data) {
        errorMsg = String(err.response.data);
      } else if (err.message) {
        errorMsg = err.message;
      }

      setError(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-background to-muted/20 p-4">
      <Card className="w-full max-w-md">
        <CardHeader className="space-y-2 text-center">
          <div className="flex justify-center mb-4">
            <div className="w-12 h-12 rounded-lg gradient-primary flex items-center justify-center">
              <BookOpen className="w-6 h-6 text-primary-foreground" />
            </div>
          </div>
          <CardTitle className="text-2xl">Excellent Training</CardTitle>
          <p className="text-sm text-muted-foreground">Gestion de Formation - Green Building</p>
        </CardHeader>

        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            {error && (
              <div className="p-3 bg-destructive/10 text-destructive text-sm rounded-md">
                {error}
              </div>
            )}

            <div className="space-y-2">
              <label className="text-sm font-medium">Rôle</label>
              <select
                value={selectedRole}
                onChange={(e) => handleRoleChange(e.target.value)}
                disabled={isLoading}
                className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
              >
                <option value="simple_utilisateur">Simple utilisateur</option>
                <option value="responsable">Responsable</option>
                <option value="administrateur">Administrateur</option>
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium">Login</label>
              <Input
                value={login}
                onChange={(e) => setLogin(e.target.value)}
                placeholder="Entrez votre login"
                disabled={isLoading}
              />
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium">Mot de passe</label>
              <Input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Entrez votre mot de passe"
                disabled={isLoading}
              />
            </div>

            <Button type="submit" className="w-full" disabled={isLoading}>
              {isLoading ? "Connexion..." : "Se connecter"}
            </Button>

            <p className="text-xs text-center text-muted-foreground mt-4">
              Identifiants de test: <strong>admin</strong> / <strong>admin123</strong>
            </p>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

export default Login;

import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "@/context/AuthContext";
import API from "@/services/api";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { BookOpen } from "lucide-react";
import { getDefaultRoute, normalizeRole } from "@/lib/rbac";

function Login() {
  const [login, setLogin] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();
  const { login: authLogin } = useAuth();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setIsLoading(true);

    if (!login.trim() || !password.trim()) {
      setError("Veuillez remplir tous les champs");
      setIsLoading(false);
      return;
    }

    try {
      console.log(" Tentative de connexion...", { login: login.trim() });
      const res = await API.post("/auth/login", { login: login.trim(), password: password.trim() });
      console.log("✅ Login réussi!", res.data);

      // Support both {token, role, login} and common legacy key names.
      const payload = {
        token: res.data?.token ?? res.data?.accessToken ?? res.data?.jwt,
        role: res.data?.role ?? res.data?.user?.role?.nom,
        login: res.data?.login ?? res.data?.username ?? login.trim(),
      };

      // Keep demo/test accounts deterministic even if backend role label is inconsistent.
      const loginKey = String(payload.login ?? "").trim().toLowerCase();
      const roleByLogin: Record<string, string> = {
        simple: "simple_utilisateur",
        responsable: "responsable",
        admin: "administrateur",
      };
      const resolvedRole = roleByLogin[loginKey] ?? payload.role;

      authLogin({ ...payload, role: resolvedRole });

      const targetRoute = getDefaultRoute(normalizeRole(resolvedRole));

      console.log(` Redirection vers ${targetRoute}...`);
      navigate(targetRoute, { replace: true });
    } catch (err: any) {
      console.error("❌ Erreur login complète:", err);
      let errorMsg = "Erreur de connexion";

      if (err.code === "ECONNABORTED") {
        errorMsg = "Timeout - Le serveur ne répond pas";
      } else if (err.message === "Network Error") {
        errorMsg = "Erreur réseau - Le backend est-il disponible?";
      } else if (err.response?.status === 401) {
        errorMsg = "Login ou mot de passe incorrect";
      } else if (err.response?.data) {
        errorMsg = String(err.response.data);
      } else if (err.message) {
        errorMsg = err.message;
      }

      setError(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-background to-muted/20 p-4">
      <Card className="w-full max-w-md">
        <CardHeader className="space-y-2 text-center">
          <div className="flex justify-center mb-4">
            <div className="w-12 h-12 rounded-lg gradient-primary flex items-center justify-center">
              <BookOpen className="w-6 h-6 text-primary-foreground" />
            </div>
          </div>
          <CardTitle className="text-2xl">Excellent Training</CardTitle>
          <p className="text-sm text-muted-foreground">Gestion de Formation - Green Building</p>
        </CardHeader>

        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            {error && (
              <div className="p-3 bg-destructive/10 text-destructive text-sm rounded-md">
                {error}
              </div>
            )}

            <div className="space-y-2">
              <label className="text-sm font-medium">Login</label>
              <Input
                value={login}
                onChange={(e) => setLogin(e.target.value)}
                placeholder="Entrez votre login"
                disabled={isLoading}
              />
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium">Mot de passe</label>
              <Input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Entrez votre mot de passe"
                disabled={isLoading}
              />
            </div>

            <Button type="submit" className="w-full" disabled={isLoading}>
              {isLoading ? "Connexion..." : "Se connecter"}
            </Button>

            <p className="text-xs text-center text-muted-foreground mt-4">
              Identifiants de test: <strong>admin</strong> / <strong>admin123</strong>
            </p>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

