import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import CrudFormModal from "@/components/shared/CrudFormModal";
import API from "@/services/api";
import { Utilisateur } from "@/types";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";

const ROLE_OPTIONS = [
  { id: 1, nom: "simple_utilisateur" },
  { id: 2, nom: "responsable" },
  { id: 3, nom: "administrateur" },
];

const UtilisateursPage = () => {
  const [utilisateurs, setUtilisateurs] = useState<Utilisateur[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUtilisateur, setEditingUtilisateur] = useState<Utilisateur | null>(null);
  const [formValues, setFormValues] = useState<Record<string, string>>({
    login: "",
    password: "",
    roleId: "3",
  });
  const [formError, setFormError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  const notify = (title: string, description: string) =>
    toast({ id: Date.now().toString(), title, description });

  useEffect(() => {
    loadUtilisateurs();
  }, []);

  const loadUtilisateurs = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/utilisateurs");
      setUtilisateurs(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de charger les utilisateurs");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (utilisateur: Utilisateur) => {
    try {
      await API.delete(`/utilisateurs/${utilisateur.id}`);
      notify("Succès", "Utilisateur supprimé");
      loadUtilisateurs();
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de supprimer l'utilisateur");
    }
  };

  const openAddModal = () => {
    setEditingUtilisateur(null);
    setFormValues({ login: "", password: "", roleId: "3" });
    setFormError("");
    setIsModalOpen(true);
  };

  const openEditModal = (utilisateur: Utilisateur) => {
    setEditingUtilisateur(utilisateur);
    setFormValues({
      login: utilisateur.login ?? "",
      password: "",
      roleId: utilisateur.role?.id ? String(utilisateur.role.id) : "3",
    });
    setFormError("");
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    const login = formValues.login.trim();
    const password = formValues.password.trim();
    const roleId = Number(formValues.roleId);

    if (!login || !password) {
      setFormError("Login et mot de passe sont obligatoires");
      return;
    }
    if (!Number.isInteger(roleId) || !ROLE_OPTIONS.some((r) => r.id === roleId)) {
      setFormError("Rôle invalide");
      return;
    }

    setIsSubmitting(true);
    setFormError("");
    try {
      const payload = {
        id: editingUtilisateur?.id,
        login,
        password,
        role: { id: roleId },
      };

      if (editingUtilisateur) {
        await API.put(`/utilisateurs/${editingUtilisateur.id}`, payload);
        notify("Succès", "Utilisateur modifié");
      } else {
        await API.post("/utilisateurs", payload);
        notify("Succès", "Utilisateur ajouté");
      }
      setIsModalOpen(false);
      loadUtilisateurs();
    } catch (error) {
      console.error("Erreur:", error);
      setFormError(editingUtilisateur ? "Impossible de modifier l'utilisateur" : "Impossible d'ajouter l'utilisateur");
    } finally {
      setIsSubmitting(false);
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "login", label: "Login" },
    {
      key: "password",
      label: "Mot de passe",
      render: () => <Badge variant="outline">••••••••</Badge>,
    },
    {
      key: "role",
      label: "Rôle",
      render: (u: Utilisateur) => (u.role ? `#${u.role.id} - ${u.role.nom}` : "—"),
    },
    {
      key: "roleId",
      label: "Rôle ID",
      render: (u: Utilisateur) => u.role?.id ?? "—",
    },
  ];

  return (
    <>
      <DataTable<Utilisateur>
        title="Utilisateurs"
        description="Gérer les utilisateurs du système"
        columns={columns}
        data={utilisateurs}
        searchKey="login"
        searchPlaceholder="Rechercher un utilisateur..."
        isLoading={isLoading}
        onAdd={openAddModal}
        onEdit={openEditModal}
        onDelete={handleDelete}
      />
      <CrudFormModal
        open={isModalOpen}
        title={editingUtilisateur ? "Modifier un utilisateur" : "Ajouter un utilisateur"}
        fields={[
          { key: "login", label: "Login", required: true },
          { key: "password", label: editingUtilisateur ? "Nouveau mot de passe" : "Mot de passe", type: "password", required: true },
          {
            key: "roleId",
            label: "Rôle",
            type: "select",
            required: true,
            options: ROLE_OPTIONS.map((r) => ({ value: String(r.id), label: `${r.nom}` })),
          },
        ]}
        values={formValues}
        error={formError}
        isSubmitting={isSubmitting}
        submitLabel={editingUtilisateur ? "Modifier" : "Ajouter"}
        onChange={(key, value) => setFormValues((prev) => ({ ...prev, [key]: value }))}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleSubmit}
      />
    </>
  );
};

export default UtilisateursPage;

import axios, { AxiosInstance, AxiosError } from "axios";

const API: AxiosInstance = axios.create({
  baseURL: "http://localhost:8080/api",
  headers: {
    "Content-Type": "application/json",
  },
  timeout: 10000, // 10 secondes timeout
});

// ========== REQUEST INTERCEPTOR ==========
API.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("token");
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    console.error("❌ Request Error:", error.message);
    return Promise.reject(error);
  }
);

// ========== RESPONSE INTERCEPTOR ==========
API.interceptors.response.use(
  (response) => {
    console.log("✅ API Response Success:", response.status, response.config.url);
    return response;
  },
  (error: AxiosError) => {
    const status = error.response?.status;
    const message = error.message;

    console.error("❌ API Error:", {
      status,
      message,
      url: error.config?.url,
      method: error.config?.method,
    });

    // Gestion des erreurs spécifiques
    if (!error.response) {
      // Erreur de connexion (backend injoignable)
      console.error(" CRITICAL: Impossible de se connecter au backend (http://localhost:8080)");
      console.error("Vérifiez que le backend est bien lancé sur le port 8080");
    } else if (status === 401) {
      // Token expiré ou invalide
      console.warn("⚠️ Session expirée (401)");
      localStorage.clear();
      window.location.href = "/login";
    } else if (status === 403) {
      // Accès non autorisé
      console.error(" Accès non autorisé (403)");
      window.location.href = "/forbidden";
    } else if (status === 404) {
      // Endpoint non trouvé
      console.error(" Endpoint non trouvé (404)");
    } else if (status === 500) {
      // Erreur serveur
      console.error(" Erreur serveur (500)");
    }

    return Promise.reject(error);
  }
);

export default API;

import axios, { AxiosInstance, AxiosError } from "axios";

const API: AxiosInstance = axios.create({
  baseURL: "http://localhost:8080/api",
  headers: {
    "Content-Type": "application/json",
  },
  timeout: 10000, // 10 secondes timeout
});

// ========== REQUEST INTERCEPTOR ==========
API.interceptors.request.use(
  (config) => {
    const url = config.url ?? "";
    const isPublicAuthEndpoint = url.includes("/auth/login") || url.includes("/auth/health");
    const token = localStorage.getItem("token");
    if (token && !isPublicAuthEndpoint) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    console.error("❌ Request Error:", error.message);
    return Promise.reject(error);
  }
);

// ========== RESPONSE INTERCEPTOR ==========
API.interceptors.response.use(
  (response) => {
    console.log("✅ API Response Success:", response.status, response.config.url);
    return response;
  },
  (error: AxiosError) => {
    const status = error.response?.status;
    const message = error.message;
    const requestUrl = error.config?.url ?? "";
    const isPublicAuthEndpoint = requestUrl.includes("/auth/login") || requestUrl.includes("/auth/health");

    console.error("❌ API Error:", {
      status,
      message,
      url: requestUrl,
      method: error.config?.method,
    });

    // Gestion des erreurs spécifiques
    if (!error.response) {
      // Erreur de connexion (backend injoignable)
      console.error(" CRITICAL: Impossible de se connecter au backend (http://localhost:8080)");
      console.error("Vérifiez que le backend est bien lancé sur le port 8080");
    } else if (status === 401 && !isPublicAuthEndpoint) {
      // Token expiré ou invalide
      console.warn("⚠️ Session expirée (401)");
      localStorage.clear();
      window.location.href = "/login";
    } else if (status === 403 && !isPublicAuthEndpoint) {
      // Accès non autorisé
      console.error(" Accès non autorisé (403)");
    } else if (status === 404) {
      // Endpoint non trouvé
      console.error(" Endpoint non trouvé (404)");
    } else if (status === 500) {
      // Erreur serveur
      console.error(" Erreur serveur (500)");
    }

    return Promise.reject(error);
  }
);

