package com.gestion.formation.entity;

import jakarta.persistence.*;
import jakarta.validation.constraints.*;
import com.fasterxml.jackson.annotation.JsonIgnore;
import java.util.List;

@Entity
@Table(name = "formations")
public class Formation {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @NotBlank
    @Column(nullable = false)
    private String titre;

    @NotBlank
    @Column(nullable = false)
    private String nom;

    @NotBlank
    @Column(nullable = false)
    private String description;

    @Min(2000)
    @Column(nullable = false)
    private Integer annee;

    @Min(1)
    @Column(nullable = false)
    private Integer duree;

    @PositiveOrZero
    private Double budget;

    @ManyToOne(fetch = FetchType.EAGER, optional = true)
    @JoinColumn(name = "id_domaine")
    private Domaine domaine;

    @ManyToOne(fetch = FetchType.EAGER, optional = true)
    @JoinColumn(name = "id_formateur")
    private Formateur formateur;

    @ManyToMany(fetch = FetchType.LAZY)
    @JoinTable(
        name = "formation_participant",
        joinColumns = @JoinColumn(name = "id_formation"),
        inverseJoinColumns = @JoinColumn(name = "id_participant")
    )
    @JsonIgnore
    private List<Participant> participants;

    public Formation() {}

    public Formation(Long id, String titre, String nom, String description, Integer annee, Integer duree, Double budget, Domaine domaine, Formateur formateur, List<Participant> participants) {
        this.id = id;
        this.titre = titre;
        this.nom = nom;
        this.description = description;
        this.annee = annee;
        this.duree = duree;
        this.budget = budget;
        this.domaine = domaine;
        this.formateur = formateur;
        this.participants = participants;
    }

    public Long getId() { return id; }
    public void setId(Long id) { this.id = id; }

    public String getTitre() { return titre; }
    public void setTitre(String titre) { this.titre = titre; }

    public String getNom() { return nom; }
    public void setNom(String nom) { this.nom = nom; }

    public String getDescription() { return description; }
    public void setDescription(String description) { this.description = description; }

    public Integer getAnnee() { return annee; }
    public void setAnnee(Integer annee) { this.annee = annee; }

    public Integer getDuree() { return duree; }
    public void setDuree(Integer duree) { this.duree = duree; }

    public Double getBudget() { return budget; }
    public void setBudget(Double budget) { this.budget = budget; }

    public Domaine getDomaine() { return domaine; }
    public void setDomaine(Domaine domaine) { this.domaine = domaine; }

    public Formateur getFormateur() { return formateur; }
    public void setFormateur(Formateur formateur) { this.formateur = formateur; }

    public List<Participant> getParticipants() { return participants; }
    public void setParticipants(List<Participant> participants) { this.participants = participants; }
}

package com.gestion.formation.entity;

import jakarta.persistence.*;
import jakarta.validation.constraints.*;
import com.fasterxml.jackson.annotation.JsonIgnore;
import java.time.LocalDate;
import java.util.List;

@Entity
@Table(name = "formations")
public class Formation {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @NotBlank
    @Column(nullable = false)
    private String titre;

    @NotBlank
    @Column(nullable = false)
    private String nom;

    @NotBlank
    @Column(nullable = false)
    private String description;

    @Min(2000)
    @Column(nullable = false)
    private Integer annee;

    @Min(1)
    @Column(nullable = false)
    private Integer duree;

    @PositiveOrZero
    private Double budget;

    @Column(name = "date_formation")
    private LocalDate dateFormation;

    @Column
    private String lieu;

    @ManyToOne(fetch = FetchType.EAGER, optional = true)
    @JoinColumn(name = "id_domaine")
    private Domaine domaine;

    @ManyToOne(fetch = FetchType.EAGER, optional = true)
    @JoinColumn(name = "id_formateur")
    private Formateur formateur;

    @ManyToMany(fetch = FetchType.LAZY)
    @JoinTable(
        name = "formation_participant",
        joinColumns = @JoinColumn(name = "id_formation"),
        inverseJoinColumns = @JoinColumn(name = "id_participant")
    )
    @JsonIgnore
    private List<Participant> participants;

    public Formation() {}

    public Formation(Long id, String titre, String nom, String description, Integer annee, Integer duree, Double budget, LocalDate dateFormation, String lieu, Domaine domaine, Formateur formateur, List<Participant> participants) {
        this.id = id;
        this.titre = titre;
        this.nom = nom;
        this.description = description;
        this.annee = annee;
        this.duree = duree;
        this.budget = budget;
        this.dateFormation = dateFormation;
        this.lieu = lieu;
        this.domaine = domaine;
        this.formateur = formateur;
        this.participants = participants;
    }

    public Long getId() { return id; }
    public void setId(Long id) { this.id = id; }

    public String getTitre() { return titre; }
    public void setTitre(String titre) { this.titre = titre; }

    public String getNom() { return nom; }
    public void setNom(String nom) { this.nom = nom; }

    public String getDescription() { return description; }
    public void setDescription(String description) { this.description = description; }

    public Integer getAnnee() { return annee; }
    public void setAnnee(Integer annee) { this.annee = annee; }

    public Integer getDuree() { return duree; }
    public void setDuree(Integer duree) { this.duree = duree; }

    public Double getBudget() { return budget; }
    public void setBudget(Double budget) { this.budget = budget; }

    public LocalDate getDateFormation() { return dateFormation; }
    public void setDateFormation(LocalDate dateFormation) { this.dateFormation = dateFormation; }

    public String getLieu() { return lieu; }
    public void setLieu(String lieu) { this.lieu = lieu; }

    public Domaine getDomaine() { return domaine; }
    public void setDomaine(Domaine domaine) { this.domaine = domaine; }

    public Formateur getFormateur() { return formateur; }
    public void setFormateur(Formateur formateur) { this.formateur = formateur; }

    public List<Participant> getParticipants() { return participants; }
    public void setParticipants(List<Participant> participants) { this.participants = participants; }
}

package com.gestion.formation.service;

import com.gestion.formation.repository.FormationRepository;
import com.gestion.formation.repository.ParticipantRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import java.util.*;

@Service
public class StatistiqueService {

    @Autowired
    private FormationRepository formationRepository;

    @Autowired
    private ParticipantRepository participantRepository;

    public Map<String, Object> getStatistiques() {
        Map<String, Object> stats = new HashMap<>();
        stats.put("totalFormations", formationRepository.count());
        stats.put("totalParticipants", participantRepository.count());
        return stats;
    }
}

package com.gestion.formation.service;

import com.gestion.formation.entity.Formation;
import com.gestion.formation.entity.Participant;
import com.gestion.formation.repository.FormationRepository;
import com.gestion.formation.repository.ParticipantRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.stream.Collectors;

@Service
public class StatistiqueService {

    @Autowired
    private FormationRepository formationRepository;

    @Autowired
    private ParticipantRepository participantRepository;

    public Map<String, Object> getStatistiques() {
        List<Formation> formations = formationRepository.findAll();
        List<Participant> participants = participantRepository.findAll();

        Map<String, Object> stats = new LinkedHashMap<>();

        // Existing metrics kept unchanged for backward compatibility
        stats.put("totalFormations", (long) formations.size());
        stats.put("totalParticipants", (long) participants.size());

        // Additional advanced indicators
        double totalBudget = formations.stream()
                .map(Formation::getBudget)
                .filter(Objects::nonNull)
                .mapToDouble(Double::doubleValue)
                .sum();
        stats.put("totalBudget", totalBudget);
        stats.put("budgetMoyen", formations.isEmpty() ? 0.0 : totalBudget / formations.size());

        stats.put("formationsParDomaine", buildFormationsParDomaine(formations));
        stats.put("participantsParStructure", buildParticipantsParStructure(participants));
        stats.put("formationsParAnnee", buildFormationsParAnnee(formations));

        return stats;
    }

    private List<Map<String, Object>> buildFormationsParDomaine(List<Formation> formations) {
        Map<String, List<Formation>> grouped = formations.stream()
                .collect(Collectors.groupingBy(f -> {
                    if (f.getDomaine() == null) {
                        return "0::Sans domaine";
                    }
                    return f.getDomaine().getId() + "::" + f.getDomaine().getLibelle();
                }));

        List<Map<String, Object>> result = new ArrayList<>();
        grouped.forEach((key, items) -> {
            String[] parts = key.split("::", 2);
            int domaineId = Integer.parseInt(parts[0]);
            String domaine = parts.length > 1 ? parts[1] : "Sans domaine";
            double budgetTotal = items.stream()
                    .map(Formation::getBudget)
                    .filter(Objects::nonNull)
                    .mapToDouble(Double::doubleValue)
                    .sum();

            Map<String, Object> row = new HashMap<>();
            row.put("domaineId", domaineId == 0 ? null : domaineId);
            row.put("domaine", domaine);
            row.put("count", items.size());
            row.put("budgetTotal", budgetTotal);
            result.add(row);
        });

        result.sort(Comparator.comparing((Map<String, Object> m) -> (Integer) m.get("count")).reversed());
        return result;
    }

    private List<Map<String, Object>> buildParticipantsParStructure(List<Participant> participants) {
        Map<String, List<Participant>> grouped = participants.stream()
                .collect(Collectors.groupingBy(p -> {
                    if (p.getStructure() == null) {
                        return "0::Sans structure";
                    }
                    return p.getStructure().getId() + "::" + p.getStructure().getLibelle();
                }));

        List<Map<String, Object>> result = new ArrayList<>();
        grouped.forEach((key, items) -> {
            String[] parts = key.split("::", 2);
            int structureId = Integer.parseInt(parts[0]);
            String structure = parts.length > 1 ? parts[1] : "Sans structure";

            Map<String, Object> row = new HashMap<>();
            row.put("structureId", structureId == 0 ? null : structureId);
            row.put("structure", structure);
            row.put("count", items.size());
            result.add(row);
        });

        result.sort(Comparator.comparing((Map<String, Object> m) -> (Integer) m.get("count")).reversed());
        return result;
    }

    private List<Map<String, Object>> buildFormationsParAnnee(List<Formation> formations) {
        Map<Integer, List<Formation>> grouped = formations.stream()
                .collect(Collectors.groupingBy(Formation::getAnnee));

        List<Map<String, Object>> result = new ArrayList<>();
        grouped.forEach((annee, items) -> {
            double budgetTotal = items.stream()
                    .map(Formation::getBudget)
                    .filter(Objects::nonNull)
                    .mapToDouble(Double::doubleValue)
                    .sum();

            Map<String, Object> row = new HashMap<>();
            row.put("annee", annee);
            row.put("count", items.size());
            row.put("budgetTotal", budgetTotal);
            result.add(row);
        });

        result.sort(Comparator.comparing((Map<String, Object> m) -> (Integer) m.get("annee")));
        return result;
    }
}

